37	// Known prefixes for ._prefix_value_. identifiers.
38	const (
39		prefixLanguage     = "language_"
40		prefixVersion      = "version_"
41		prefixRole         = "role_"
42		prefixOutputFormat = "outputformat_"
43		prefixKind         = "kind_"
44		prefixLayout       = "layout_"
45	)
