185	type PathParser struct {
186		// Maps the language code to its index in the languages/sites slice.
187		LanguageIndex map[string]int
188	
189		// Reports whether the given language is disabled.
190		IsLangDisabled func(string) bool
191	
192		// IsOutputFormat reports whether the given name is a valid output format.
193		// The second argument is optional.
194		IsOutputFormat func(name, ext string) bool
195	
