213	// NormalizePathString returns a normalized path string using the very basic Hugo rules.
214	func NormalizePathStringBasic(s string) string {
215		// All lower case.
216		s = strings.ToLower(s)
217	
218		// Replace spaces with hyphens.
219		s = strings.ReplaceAll(s, " ", "-")
220	
221		return s
222	}
