466	func (pp *PathParser) doParse(component, s string, p *Path) (*Path, error) {
467		if runtime.GOOS == "windows" {
468			s = path.Clean(filepath.ToSlash(s))
469			if s == "." {
470				s = ""
471			}
472		}
473	
474		if s == "" {
475			s = "/"
476		}
477	
478		// Leading slash, no trailing slash.
479		if !strings.HasPrefix(s, "/") {
480			s = "/" + s
481		}
482	
483		if s != "/" && s[len(s)-1] == '/' {
484			s = s[:len(s)-1]
485		}
486	
487		p.s = s
488	
489		// Find dots inside ._..._. wrapper blocks that must be skipped.
490		skipDots := findWrapperDotPositions(s)
491	
492		slashCount := 0
493		lastDot := 0
494		lastSlashIdx := strings.LastIndex(s, "/")
495		numDots := strings.Count(s[lastSlashIdx+1:], ".") - len(skipDots)
496		if strings.Contains(s, "/_shortcodes/") {
497			p.pathType = TypeShortcode
498		}
499	
500		for i := len(s) - 1; i >= 0; i-- {
501			c := s[i]
502	
503			switch c {
504			case '.':
505				if isSkippedDot(skipDots, i) {
506					continue
507				}
508				pp.parseIdentifier(component, s, p, i, lastDot, numDots, false)
509				lastDot = i
510			case '/':
511				slashCount++
512				if p.posContainerHigh == -1 {
513					if lastDot > 0 {
514						pp.parseIdentifier(component, s, p, i, lastDot, numDots, true)
515					}
516					p.posContainerHigh = i + 1
517				} else if p.posContainerLow == -1 {
518					p.posContainerLow = i + 1
519				}
520				if i > 0 {
521					p.posSectionHigh = i
522				}
523			}
524		}
525	
526		// Compute the name boundary.
527		if p.posNameHigh >= p.posContainerHigh {
528			p.posIdentifierName = types.LowHigh[string]{Low: p.posContainerHigh, High: p.posNameHigh}
529		} else {
530			p.posIdentifierName = types.LowHigh[string]{Low: p.posContainerHigh, High: len(p.s)}
531		}
532	
533		if len(p.identifiersKnown) > 0 {
534			isContentComponent := p.component == files.ComponentFolderContent || p.component == files.ComponentFolderArchetypes
535			isContent := isContentComponent && pp.IsContentExt(p.Ext())
536	
537			if p.posIdentifierName.Low >= p.posContainerHigh && p.posIdentifierName.High > p.posIdentifierName.Low {
538				b := p.s[p.posIdentifierName.Low:p.posIdentifierName.High]
539				if isContent {
540					switch b {
541					case "index":
542						p.pathType = TypeLeaf
543					case "_index":
544						p.pathType = TypeBranch
545					default:
546						p.pathType = TypeContentSingle
547					}
548	
549					if slashCount == 2 && p.IsLeafBundle() {
550						p.posSectionHigh = 0
551					}
552				} else if b == files.NameContentData && files.IsContentDataExt(p.Ext()) {
553					p.pathType = TypeContentData
554				}
555			}
556		}
557	
558		if p.pathType < TypeMarkup && component == files.ComponentFolderLayouts {
559			if p.posIdentifierBaseof != -1 {
560				p.pathType = TypeBaseof
561			} else {
562				pth := p.Path()
563				if strings.Contains(pth, "/_shortcodes/") {
564					p.pathType = TypeShortcode
565				} else if strings.Contains(pth, "/_markup/") {
566					p.pathType = TypeMarkup
567				} else if strings.HasPrefix(pth, "/_partials/") {
568					p.pathType = TypePartial
569				}
570			}
571		}
572	
573		if p.pathType == TypeShortcode && p.posIdentifierLayout != -1 {
574			id := p.identifiersKnown[p.posIdentifierLayout]
575			if id.Low == p.posContainerHigh {
576				// First identifier is shortcode name.
577				p.posIdentifierLayout = -1
578			}
579		}
580	
581		return p, nil
582	}
583	
584	func ModifyPathBundleTypeResource(p *Path) {
585		if p.IsContent() {
586			p.pathType = TypeContentResource
587		} else {
588			p.pathType = TypeFile
589		}
590	}
