	for _, i := range idxs {
		s.s.versions.Set(i)
	}
	return s
}

func (s *IntSetsBuilder) WithRoleIndices(idxs ...int) *IntSetsBuilder {
	if len(idxs) == 0 {
		return s
	}
	if s.s.roles == nil {
		s.s.roles = hmaps.NewOrderedIntSet()
